function variablesDecode(data)
            {
                var tmp = data.split('_');
                var value = tmp[1];
                switch (tmp[0])
                {
                    case 'fl':
                        tmp[1] = "0x" + tmp[1];
                        value = _hex2float(tmp[1]);
                        value = Math.round(value * 100) / 100;
                        break;
                    case 'u8':
                        //alert("u8");
                        value = _hex2dec(value);
                        if (value < 10)
                        {
                            value = "0" + value;
                        }
                        break;
                    case 'u1':
                        //alert("u1");
                        value = _hex2dec(value);
                        if (value < 10)
                        {
                            value = "0" + value;
                        }
                        break;
                    case 'u3':
                        value = _hex2dec(value);
                        break;
                    case 'u6':
                        value = _hex2dec(value);
                        break;
                    case 'i1':
                        value = parseInt(value, 16);

                        if(!isNaN(value)) {
                            if (value < 10) {
                                value = "0" + value;
                            }
                            if ((value & 0x8000) > 0) {
                                value = value - 0x10000;
                            }
                        }
                        else  {
                            value = NaN;
                        }
                        break;
                    case 'i3':
                        value = parseInt(value, 16);
                        if(!isNaN(value))
                        {
                            if (value < 10) {
                                value = "0" + value;
                            }

                            if ((Math.abs(value & 0x80000000)) > 0) {
                                value = value - 0x100000000;
                            }
                        }
                        else  {
                            value = NaN;
                        }

                        break;
                    case 'i8':
                        value = parseInt(value, 16);
                        if (value < 10) {
                            value = "0" + value;
                        }
                        if ((value & 0x80) > 0) {
                            value = value - 0x100;
                        }
                        break;
                    case 'ch':
                        //alert("ch");
                        break;
                    case 'st':
                        //alert("st");
                        break;
                    case 'er':
                        console.log("error: " + data);
                        break;
                    default:
                        console.log("error: unknown variable type: " + data);
                        break;
                }

                return value;

                function _hex2float(num) {
                    var sign = (num & 0x80000000) ? -1 : 1;
                    var exponent = ((num >> 23) & 0xff) - 127;
                    var mantissa = ((num & 0x7fffff) + 0x800000).toString(2); // binary
                    var float = 0;
                    // Convert to float
                    for (var i=0; i<mantissa.length; i+=1)
                    {
                        float += parseInt(mantissa[i])? Math.pow(2,exponent):0;
                        exponent--;
                    }
                    return sign * float;
                }

                function _hex2dec(num)
                {
                    return parseInt(num, 16);
                }
            }

