newMsg = null;
if(msg.payload.Tesla.drive_state.latitude >= 51.01 &&
    msg.payload.Tesla.drive_state.latitude <= 51.04 &&
    msg.payload.Tesla.drive_state.longitude >= 6.9 &&
    msg.payload.Tesla.drive_state.longitude <= 7.1 &&
    msg.payload.Tesla.charge_state.charge_port_latch == "Engaged" &&
    msg.payload.Surplus == true){
        if(msg.amps  >= 2 && 
        msg.payload.Tesla.charge_state.charging_state == "Stopped"){
            msg.command = "startCharge"
        } else if (msg.amps  < 2 && 
        msg.payload.Tesla.charge_state.charging_state == "Charging"){
            msg.command = "stopCharge" 
            msg.amps = 0
        }
    newMsg = { "commandArgs": {"amps": msg.amps},
                "command": msg.command };
}

return newMsg;
